import json

with open('ios_crash.ips') as f:
    lines = f.readlines()
crash = json.loads(''.join(lines[1:]))

images = crash['usedImages']
faulting = crash['faultingThread']

dotnet_indices = set()
dotnet_libs = ['libcoreclr', 'libmonosgen', 'libSystem.Native', 'libSystem.Globalization', 
               'libSystem.Security.Cryptography', 'libSystem.IO.Compression', 'libSystem.Net.Security']
for i, img in enumerate(images):
    name = img.get('name', '')
    if any(lib in name for lib in dotnet_libs) or name == 'SampleMAUI':
        dotnet_indices.add(i)

# Show faulting thread frames
print(f"=== FAULTING THREAD {faulting} FRAMES ===")
ft = crash['threads'][faulting]
for i, frame in enumerate(ft['frames']):
    img_idx = frame['imageIndex']
    img = images[img_idx]
    addr = img['base'] + frame['imageOffset']
    marker = " <<<.NET>>>" if img_idx in dotnet_indices else ""
    print(f"  #{i:2d} {img['name']:45s} 0x{addr:x}{marker}")

# Show lastExceptionBacktrace if present
if 'lastExceptionBacktrace' in crash:
    print(f"\n=== LAST EXCEPTION BACKTRACE ===")
    for i, frame in enumerate(crash['lastExceptionBacktrace']['frames']):
        img_idx = frame['imageIndex']
        img = images[img_idx]
        addr = img['base'] + frame['imageOffset']
        marker = " <<<.NET>>>" if img_idx in dotnet_indices else ""
        print(f"  #{i:2d} {img['name']:45s} 0x{addr:x}{marker}")

# Collect .NET frames needing symbolication from faulting thread
print(f"\n=== .NET FRAMES NEEDING SYMBOLICATION (Faulting Thread) ===")
frames_by_image = {}
for i, frame in enumerate(ft['frames']):
    img_idx = frame['imageIndex']
    if img_idx in dotnet_indices:
        img = images[img_idx]
        addr = img['base'] + frame['imageOffset']
        name = img['name']
        if name not in frames_by_image:
            frames_by_image[name] = {'base': img['base'], 'uuid': img['uuid'].replace('-','').lower(), 'arch': img.get('arch','arm64'), 'addrs': []}
        frames_by_image[name]['addrs'].append((i, addr))

for name, info in frames_by_image.items():
    print(f"\n  {name} (UUID: {info['uuid']}, base: 0x{info['base']:x})")
    for frame_num, addr in info['addrs']:
        print(f"    Frame #{frame_num}: 0x{addr:x}")

# Also do lastExceptionBacktrace
if 'lastExceptionBacktrace' in crash:
    print(f"\n=== .NET FRAMES NEEDING SYMBOLICATION (Exception Backtrace) ===")
    frames_by_image2 = {}
    for i, frame in enumerate(crash['lastExceptionBacktrace']['frames']):
        img_idx = frame['imageIndex']
        if img_idx in dotnet_indices:
            img = images[img_idx]
            addr = img['base'] + frame['imageOffset']
            name = img['name']
            if name not in frames_by_image2:
                frames_by_image2[name] = {'base': img['base'], 'uuid': img['uuid'].replace('-','').lower(), 'arch': img.get('arch','arm64'), 'addrs': []}
            frames_by_image2[name]['addrs'].append((i, addr))

    for name, info in frames_by_image2.items():
        print(f"\n  {name} (UUID: {info['uuid']}, base: 0x{info['base']:x})")
        for frame_num, addr in info['addrs']:
            print(f"    Frame #{frame_num}: 0x{addr:x}")

